create table dirkspzm32.bde_pd_prod (
    sid                     varchar2(2 char) not null enable,
    vorg_id                 number(*, 0) not null enable,
    vorg_typ                varchar2(2 char) not null enable,
    firma_nr                number(2, 0) not null enable,
    leitzahl                number(*, 5) not null enable,
    fa_ag                   number(*, 0) not null enable,
    fa_upos                 number(*, 0),
    abnr                    varchar2(20 char),
    res_id                  number(*, 0) not null enable,
    prod_beginn             date not null enable,
    prod_ende               date,
    pers_nr                 number(*, 0),
    lam_id                  number(*, 0),
    artikel_id              number(*, 0),
    menge_a                 number(*, 3),
    menge_b                 number(*, 3),
    schrott                 number(*, 3),
    ls_login_id             number(*, 0),
    pd_netto_zeit           number(*, 12),
    abfuell_abschalt_grob   number(*, 5),
    abfuell_abschalt_mittel number(*, 5),
    abfuell_abschalt_fein   number(*, 5),
    abfuell_toleranz_plus   number(*, 6),
    abfuell_toleranz_minus  number(*, 6),
    abfuell_silo            varchar2(30 char),
    abfuell_soll            number(*, 3),
    abfuell_ist             number(*, 3),
    prod_params             varchar2(4000 char),
    fae_id                  varchar2(20 char),
    fae_id_position         varchar2(1 char),
    abfuell_tara            number(*, 3),
    abfuell_brutto          number(*, 3)
);

alter table dirkspzm32.bde_pd_prod
    add constraint pk_bde_pd_prod
        primary key ( sid,
                      vorg_typ,
                      vorg_id,
                      firma_nr,
                      leitzahl,
                      fa_ag )
            using index enable;


